        {"Topic": "2", "Subtopic": "N/A", "Front": "Resource Allocation (Asset)", "Back": "Assigning organizational budget and personnel to asset protection. ensures that critical systems receive adequate security testing and maintenance to defend against cyber threats."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Inventory Verification", "Back": "Systematic process of checking organizational asset counts. prevents loss and ensures that all hardware and software are accounted for within the security program."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Information Handling Rule", "Back": "Mandatory procedure for accessing sensitive information. ensures that organizational personnel handle all assets consistently and follow established security protocols to prevent accidental data disclosure."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Baseline Protection (Asset)", "Back": "Minimum required security controls for all organizational assets. provides a foundation for protection and ensures a consistent security posture across the entire IT environment."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Data Collection Stage", "Back": "Initial phase of the data lifecycle. requires implementing privacy controls and ensuring only necessary organizational information is gathered according to the minimization principle and goals."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Data Location Compliance", "Back": "Ensuring information is stored in legally authorized jurisdictions. essential for meeting organizational data sovereignty requirements and complying with various international and regional privacy laws."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Data Maintenance Phase", "Back": "Stage of lifecycle involving ongoing data protection. requires regular audits and monitoring to ensure organizational assets remain accurate, complete, and secured against potential threats."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Asset Retention Strategy", "Back": "Plan defining how long organizational items are kept. ensures that critical resources are available when needed while preventing the accumulation of unnecessary business risk."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Standards Selection (Asset)", "Back": "Choosing appropriate technical requirements for protection. ensures that organizational encryption and access controls are applied consistently based on classification levels and mandated compliance rules."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Host-based Security (Asset)", "Back": "Protective measures applied to individual organizational devices. includes firewalls and EDR designed to prevent malware and unauthorized access at the specific hardware endpoint level."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Information Integrity (Topic 2)", "Back": "Assurance that data is accurate and untampered. maintained through hashing and digital signatures to provide reliable and trustworthy organizational assets for critical business processing."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Asset Criticality", "Back": "Measure of how essential an item is to business. determines organizational recovery priorities and protection levels during disaster recovery planning and overall risk assessments."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Hard Copy Security (Topic 2)", "Back": "Protecting physical documents through locks and policies. ensures sensitive organizational paper-based info is not exposed to unauthorized individuals within the office or facility area."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Media Encryption (Asset)", "Back": "Using cryptography to protect data on removable media. prevents organizational information from being read if USB drives or disks are lost or stolen during transport."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Data Quality (Asset)", "Back": "The degree to which information is accurate and reliable. essential for effective organizational security monitoring and making informed business management and strategic planning decisions."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Secure Media Storage (Asset)", "Back": "Keeping devices in locked environments with restricted access. physical protection is essential for preventing unauthorized individuals from stealing or tampering with sensitive organizational hardware assets."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Compliance Assessment (Asset)", "Back": "Evaluating organizational adherence to data laws. identifies gaps in security and ensures that all mandated asset protection controls are functioning effectively to avoid penalties."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "System Hardening (Provisioning)", "Back": "Securing organizational assets by removing unnecessary services. critical task during provisioning that reduces the attack surface and strengthens the system's overall security posture and resilience."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Information Privacy Control (Asset)", "Back": "Mechanism used to protect personal organizational data. includes techniques like anonymization and masking to ensure that individual privacy is maintained during sensitive data processing activities."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Data Security Control (Asset)", "Back": "Mechanism used to protect organizational information from threats. combines technical and administrative measures to maintain confidentiality, integrity, and availability of all data assets."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Hardware Inventory (Asset)", "Back": "Tracking physical devices to prevent organizational loss. ensures that all equipment is accounted for and receives necessary security updates and maintenance throughout its functional lifecycle."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Software Inventory (Asset)", "Back": "Tracking application versions and organizational licenses. essential for maintaining compliance with vendor agreements and ensuring all programs are patched against known security vulnerabilities promptly."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Information Categorization (Asset)", "Back": "Grouping assets based on shared security needs. simplifies management by allowing organizations to apply the same protection profile to multiple similar data types and systems."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Information Asset (Topic 2)", "Back": "Any piece of valuable data owned by an organization. includes financial records and trade secrets that require systematic identification and protection throughout their existence."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Hardware Asset (Topic 2)", "Back": "Physical equipment like servers and organizational devices. these tangible components must be tracked and secured to prevent theft and maintain organizational operational business continuity."},
        {"Topic": "2", "Subtopic": "N/A", "Front": "Asset Security", "Back": "Comprehensive management of organizational information and hardware. combines classification, protection, and secure disposal to maintain confidentiality, integrity, and availability of all organizational resources."},

        # Topic 3: Security Architecture and Engineering
        {"Topic": "3", "Subtopic": "N/A", "Front": "Bell-LaPadula Model", "Back": "Confidentiality-focused state machine model. Enforces 'no read up' and 'no write down' rules to prevent unauthorized access to sensitive information at higher levels."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Biba Model", "Back": "Integrity-focused security model. Enforces 'no read down' and 'no write up' rules to prevent data corruption from lower-integrity sources or unauthorized modifications."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Clark-Wilson Model", "Back": "Commercial integrity model using well-formed transactions. Requires that all changes to data are performed through authorized programs and enforces strict organizational separation of duties."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Brewer-Nash Model", "Back": "Chinese Wall model preventing conflicts of interest. dynamically restricts access based on a user's previous organizational data access history to maintain professional and legal integrity."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Non-Interference Model", "Back": "Theoretical security model ensuring that actions at one level do not affect or reveal info to users at a lower organizational security level."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Trusted Computing Base (TCB)", "Back": "Hardware, software, and firmware critical to security policy enforcement. must be tamper-proof and thoroughly tested to ensure it provides a reliable organizational defense foundation."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Reference Monitor", "Back": "Abstract component mediating every access request to objects. verifies authorization against organizational security policy and must be always invoked, tamper-proof, and small for testing."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Security Kernel", "Back": "Hardware and software implementation of the reference monitor. must be small enough to be rigorously tested and verified for correctness in enforcing organizational protection policies."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Common Criteria (CC)", "Back": "International standard (ISO 15408) for evaluating IT security. uses EAL grades to provide a consistent measure of an organizational product's security capabilities and effectiveness."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Protection Profile (PP)", "Back": "Common Criteria document defining security needs for product categories. Enables organizational consumers to specify requirements before formal product evaluation and certification occurs."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Security Target (ST)", "Back": "Common Criteria document from a vendor. specifies security claims and technical features of an organizational product undergoing formal evaluation and verification for compliance."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "EAL (Assurance Level)", "Back": "Numerical grade (1-7) assigned after evaluation. higher levels indicate more rigorous testing and greater confidence in an organizational product's security features and design."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Trusted Platform Module (TPM)", "Back": "Hardware chip providing secure cryptographic key storage. Enables organizational hardware integrity checks and protects against firmware-level tampering and unauthorized system-level modifications and changes."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Hardware Security Module (HSM)", "Back": "Physical device protecting digital keys for strong authentication. provides highly secure cryptographic processing and prevents key extraction through physical and logical organizational barriers."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Symmetric Encryption", "Back": "Method using a single shared key for locking and unlocking. it is fast and efficient for processing large organizational information volumes and assets."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Asymmetric Encryption", "Back": "Public-key cryptography using linked key pairs. enables secure key exchange and digital signatures, ensuring confidentiality and integrity between various organizational and external parties."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Diffie-Hellman", "Back": "Key exchange algorithm for establishing shared secrets over insecure channels. provides the mathematical foundation for many secure organizational communication protocols and encrypted data sessions."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "RSA Algorithm", "Back": "Asymmetric encryption based on factoring large prime numbers. provides strong security for data encryption and digital signatures, essential for modern organizational identity and access systems."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "AES (Standard)", "Back": "Global standard for symmetric encryption. uses variable key lengths to provide robust protection for sensitive organizational data at rest across all infrastructure components."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Cryptographic Hash", "Back": "One-way function producing a unique fixed-length output. used to verify organizational data integrity by detecting any changes to the original message or information file."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Salting (Topic 3)", "Back": "Adding random data to passwords before hashing. prevents rainbow table attacks and ensures identical passwords result in unique hashes within the organizational identity system."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Digital Signature (Topic 3)", "Back": "Mechanism providing proof of origin and integrity. uses a private key to sign hashes, ensuring organizational senders cannot deny involvement in communications."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "PKI Framework", "Back": "Framework of hardware and software managing digital certificates. enables secure identity verification and encrypted communication across large distributed organizational networks and external partner systems."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Certificate Authority (Topic 3)", "Back": "Trusted entity issuing and managing digital certificates. verifies certificate holder identities and maintains revocation lists to ensure organizational platform-wide security and system integrity."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Defense in Depth (Topic 3)", "Back": "Layered approach using multiple controls to protect assets. ensures that if one barrier fails, others are in place to prevent organizational breaches."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Least Privilege (Architecture)", "Back": "Granting only minimum access needed for functions. limits potential damage from compromised accounts and is a fundamental design requirement for all organizational systems."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Secure Defaults", "Back": "Pre-configured settings providing maximum protection. requires users to explicitly enable risky features, reducing the likelihood of accidental organizational security vulnerabilities and gaps."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Fail-Safe Design", "Back": "Principle where systems default to secure states upon failure. prevents unauthorized access or organizational harm when technical components stop functioning correctly during operations."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Economy of Mechanism", "Back": "Design principle favoring simple security mechanisms. smaller codebases are easier to test and verify, reducing the probability of hidden organizational vulnerabilities and errors."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Complete Mediation (Architecture)", "Back": "Requirement that every access request must be checked. ensures that organizational security controls cannot be bypassed, even after an initial user authorization was granted."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Open Design Principle", "Back": "Security should not rely on secrecy of the mechanism. encourages peer review and robust testing to ensure organizational protections remain effective against adversaries."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Isolation (Architecture)", "Back": "Separating processes or users into distinct environments. prevents a compromise in one area from affecting other parts of the entire organizational system or network."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Ring Protection (Topic 3)", "Back": "Hierarchical CPU architecture isolating the kernel from applications. Ring 0 has highest privileges, preventing user programs from causing organizational system crashes or breaches."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Zero Trust (Architecture)", "Back": "Model assuming no entity is trusted by default. requires continuous verification of every organizational user and device, regardless of their location on the network."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Privacy by Design (Topic 3)", "Back": "Embedding privacy protections into the initial system design. ensures user confidentiality is a core requirement rather than an added organizational software or hardware feature."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "SaaS Security (Architecture)", "Back": "Protections for software-as-a-service environments. relies on strong identity management and encryption to maintain organizational control over data stored in external application environments."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "IaaS Security (Architecture)", "Back": "Protections for infrastructure-as-a-service. requires organizational management of guest operating systems and applications while the provider secures the underlying physical and virtualization hardware layers."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "PaaS Security (Architecture)", "Back": "Protections for platform-as-a-service. allows organizations to focus on application security while the provider manages and secures the underlying platform and infrastructure components."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Industrial Control Systems (Topic 3)", "Back": "Systems managing critical infrastructure like power. require specialized measures to protect against physical impacts and ensure constant organizational availability of essential public services."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Internet of Things Security", "Back": "Protecting network-connected physical devices. requires robust segmentation and regular firmware updates to prevent vulnerable organizational IoT items from becoming easy attack entry points."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Microservices Architecture", "Back": "Software design using small, independent services. simplifies security by isolating components, ensuring a breach in one service doesn't compromise the entire organizational application."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Containerization Security", "Back": "Isolating applications within lightweight containers. requires image scanning and runtime monitoring to prevent malware from spreading between different organizational workloads and information system environments."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Serverless Security", "Back": "Protecting event-driven functions in the cloud. requires granular access controls and strict monitoring of execution environments to safeguard organizational data during processing phases."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Edge Computing Security", "Back": "Distributed architecture bringing processing near data sources. requires localized security controls to protect sensitive organizational info before transmission to central corporate or cloud servers."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Virtualization Security (Topic 3)", "Back": "Controls protecting hypervisors and virtual machines. requires isolation between guest systems and monitoring for attacks attempting to escape the virtualized organizational IT environment."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Cryptographic Life Cycle", "Back": "Management of encryption from key generation to destruction. ensures that organizational information remains protected throughout its existence using up-to-date and secure algorithms."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Quantum Key Distribution", "Back": "Using quantum mechanics for secure key exchange. provides theoretical protection against future powerful computers, ensuring long-term confidentiality for sensitive organizational communication and information."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Key Management (Architecture)", "Back": "Processes protecting and controlling cryptographic keys. includes generation and rotation, ensuring only authorized organizational users can access encrypted and protected information assets."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Brute Force (Topic 3)", "Back": "Trial-and-error method to guess passwords or keys. attackers systematically try all combinations until the correct organizational system or data access credential is found."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Side-channel Attack", "Back": "Attack based on physical cryptosystem implementation. uses clues like power consumption or electromagnetic leaks to extract secret organizational cryptographic keys and bypass logical protections."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Fault Injection (Attack)", "Back": "Deliberately causing errors in hardware to bypass security. aims to trick organizational systems into an insecure state, allowing unauthorized access or key extraction."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Timing Attack", "Back": "Attack measuring the time required for cryptographic operations. clues help adversaries deduce secret organizational keys based on processing speed differences for various data inputs."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Ransomware (Architecture)", "Back": "Malware encrypting organizational files for payment. requires multi-layered defenses, including backups and endpoint protection, to prevent catastrophic data loss and business disruption."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Facility Security Control", "Back": "Physical measures protecting buildings and hardware. include cameras and barriers designed to prevent unauthorized individuals from reaching sensitive organizational areas and critical servers."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Wiring Closet Security", "Back": "Protecting network hubs and cabling from tampering. essential for preventing physical-level attacks that could compromise organizational data transmissions and overall system availability."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Environmental HVAC Controls", "Back": "Maintaining safe temperature and humidity for hardware. prevents equipment failure and ensures continuous organizational availability of critical information assets and digital infrastructure components."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Fire Suppression (Architecture)", "Back": "Systems designed to extinguish data center fires. uses gas or chemicals to protect organizational hardware from damage while ensuring personnel safety during emergencies."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Power Redundancy (Architecture)", "Back": "Using backup generators and UPS systems. ensures critical organizational functions remain available and allows for a graceful shutdown if primary utility power is lost."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "System Lifecycle Phase", "Back": "Specific stage in an asset's existence. includes design, development, and retirement, each requiring targeted organizational security controls to maintain constant information protection."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Secure Integration Phase", "Back": "Secure SDLC stage where components are combined. requires verification that all organizational modules work together securely and follow established data protection standards and policies."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Retirement/Disposal Security", "Back": "Final lifecycle phase for organizational assets. requires sanitization and destruction to prevent data breaches when old hardware or software is removed from service."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Threat Modeling Process", "Back": "Identifying and prioritizing potential system threats. uses visual representations to anticipate attack vectors and develop effective organizational risk mitigation strategies and protective measures."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Shared Responsibility Model", "Back": "Security framework for cloud services. defines protection duties for both providers and organizational customers, ensuring all layers of the IT stack are secured."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "SASE (Architecture)", "Back": "Secure Access Service Edge. Combines network security functions with WAN capabilities, providing secure organizational connectivity for remote users and cloud-based applications and services."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Memory Protection", "Back": "Technique preventing processes from accessing unauthorized RAM areas. essential for organizational system stability and preventing malicious code from stealing sensitive information from other applications."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "High-Performance Computing (HPC)", "Back": "Complex systems requiring specialized security designs. focuses on protecting large-scale data processing while maintaining the extreme operational speed needed for organizational research and development."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Pass the Hash Attack", "Back": "Stealing a hashed password to authenticate to a system. allows attackers to gain organizational access without ever knowing the original user's secret cleartext password."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Kerberos Exploitation (Topic 3)", "Back": "Attacks targeting the ticket-based authentication system. requires robust monitoring and strong organizational key management to prevent adversaries from gaining unauthorized access to network resources."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Implementation Attack (Topic 3)", "Back": "Attack exploiting flaws in how a system is built. targets specific organizational coding or configuration errors rather than theoretical weaknesses in security algorithms."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Chosen Ciphertext Attack", "Back": "Adversary selects encrypted data to be decrypted. clues from the resulting organizational plaintext help them deduce secret keys and break the cryptographic protection."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Frequency Analysis (Attack)", "Back": "Studying symbol frequency to break simple ciphers. used to identify common patterns in organizational ciphertext data and recover the original protected information."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "State Machine Model", "Back": "Security model representing a system in various states. ensures organizational transitions are secure and that information remains protected regardless of current system activity."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Information Flow Model (Topic 3)", "Back": "Mechanism regulating how data moves between systems. prevents unauthorized organizational data leakage and ensures that sensitive info stays within its mandated security boundaries."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Verification and Validation", "Back": "Secure SDLC phase ensuring software meets requirements. V&V confirms that all organizational security controls are functioning correctly and provide the intended level of protection."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Architecture Vulnerability", "Back": "Foundational flaw in system design. identifying these gaps during organizational security assessments is critical for making structural improvements and preventing multiple related vulnerabilities."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Database System Security", "Back": "Protections for organized organizational data collections. includes encryption and granular access controls designed to maintain confidentiality and integrity of all stored information assets."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Embedded Security (Topic 3)", "Back": "Protections for specialized hardware with limited resources. requires efficient organizational designs that safeguard against tampering without compromising the primary technical performance or functionality."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "HPC Security (Topic 3)", "Back": "Measures protecting large-scale computing systems. focuses on ensuring organizational data integrity and availability while maintaining the extreme processing speeds required for complex research tasks."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Virtualized Architecture", "Back": "System design using guest machines on shared hardware. requires hypervisor-level organizational security controls to maintain isolation and prevent unauthorized cross-machine information access and breaches."},
        {"Topic": "3", "Subtopic": "N/A", "Front": "Security Architecture and Engineering", "Back": "Comprehensive design and implementation of system protections. ensures that all organizational technical components work together to safeguard critical information and hardware assets."},

        # Topic 4: Communication and Network Security
        {"Topic": "4", "Subtopic": "N/A", "Front": "OSI Model", "Back": "Seven-layer conceptual framework for network communications. Standardizes how different organizational hardware and software interact, from physical connections to high-level application services."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "TCP/IP Protocol Suite", "Back": "Four-layer model powering the internet. includes Link, Internet, Transport, and Application layers, providing a practical framework for efficient organizational data transmission and connectivity."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Layer 1: Physical", "Back": "Bottom OSI layer handling hardware connections. focuses on electrical signals and cabling, requiring physical organizational security to prevent unauthorized tapping or tampering with transmissions."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Layer 2: Data Link", "Back": "OSI layer using MAC addresses for local delivery. requires port security and VLANs to prevent unauthorized organizational devices from connecting to the network segment."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Layer 3: Network", "Back": "OSI layer handling routing and IP addresses. uses firewalls and routers to direct organizational traffic securely between different networks and isolated segments and zones."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Layer 4: Transport", "Back": "OSI layer ensuring reliable data delivery. uses protocols like TCP and UDP to manage organizational connections and provide end-to-end communication and data flow control."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Layer 7: Application", "Back": "Top OSI layer interacting with software services. focuses on user-facing protocols like HTTP, requiring application-level organizational security to protect against sophisticated web-based attacks."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "IPv4 Protocol", "Back": "Legacy internet protocol with 32-bit addresses. requires NAT for space conservation and lacks built-in security, necessitating external organizational protections like IPsec for confidentiality."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "IPv6 Features", "Back": "Modern protocol with massive address space. includes built-in IPsec and improved routing, providing more efficient and secure organizational network communications and connectivity globally."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "IPsec Security", "Back": "Protocol suite authenticating and encrypting IP packets. provides strong confidentiality and integrity for organizational network traffic, essential for secure VPNs and site-to-site communication."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "SSH Protocol", "Back": "Cryptographic protocol for secure remote access. it provides strong authentication and encrypted communication, replacing insecure Telnet for managing organizational network devices and servers."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "TLS Security", "Back": "Protocol providing secure communication over networks. encrypts data between organizational applications and servers, ensuring privacy for web browsing, email, and other digital transmissions."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Converged Protocol (iSCSI)", "Back": "Storage traffic running over Ethernet networks. requires organizational security measures like network segmentation and encryption to protect sensitive data from unauthorized interception and modification."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "VoIP Security (Topic 4)", "Back": "Protecting voice communications over IP networks. requires session border controllers and encryption to prevent eavesdropping and ensure organizational communication confidentiality and availability at all times."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Topology", "Back": "Physical or logical layout of a network. includes star and mesh designs, impacting the overall reliability and organizational security of data transmissions between systems."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Control Plane", "Back": "Network layer managing routing and signaling. must be secured from unauthorized access to prevent attackers from hijacking organizational traffic flows and disrupting essential services."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Data Plane", "Back": "Layer responsible for forwarding user traffic. requires firewalls and access controls to filter and protect organizational information as it moves across the network infrastructure."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Bandwidth Metrics", "Back": "Measure of data transmission capacity. important for organizational capacity management, ensuring the network can handle traffic volume without compromising overall security performance or availability."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Latency and Jitter", "Back": "Delay and variation in packet arrival. critical metrics for real-time organizational services like VoIP, requiring traffic shaping to maintain quality and security."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Throughput (Network)", "Back": "Actual rate of successful data delivery. monitored to identify organizational network bottlenecks and detect potential DoS attacks that could overwhelm essential business services and information."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Signal-to-Noise Ratio", "Back": "Measure of signal strength against background interference. critical for organizational wireless performance and security, ensuring that communications are reliable and resistant to interception."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Traffic Flow (North-South)", "Back": "Data moving between the internal network and the internet. must be filtered by perimeter organizational firewalls to prevent unauthorized access and data breaches."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Traffic Flow (East-West)", "Back": "Data moving between internal systems or segments. requires micro-segmentation and internal organizational firewalls to prevent attackers from moving laterally after a successful perimeter breach."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "In-band Management", "Back": "Device management via the primary data channel. convenient but risky, as an organizational network compromise could also grant attackers access to sensitive hardware control interfaces."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Out-of-band Management", "Back": "Device management via a separate dedicated channel. ensures organizational administrators can access hardware even if the primary data network is down or compromised."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Air-gapped Network", "Back": "Physical isolation from any other network. provide ultimate protection for highly sensitive organizational systems that must never be connected to the public internet."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "VLAN Segmentation", "Back": "Logical network segments within a switch. it improves organizational security and performance by isolating traffic between different departments and user groups on shared hardware."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "VPN Tunneling", "Back": "Secure, encrypted connection over untrusted networks. Enables organizational users to access internal resources privately, protecting sensitive information from interception and maintaining strong data confidentiality."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Virtual Routing", "Back": "Logical separation of routing instances on hardware. enhances organizational network security by allowing traffic from different trust levels to be managed independently on shared routers."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Micro-segmentation (Network)", "Back": "Granular security technique creating secure zones around workloads. prevents lateral movement of threats within organizational data centers and complex cloud-based IT environments and systems."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Distributed Firewall", "Back": "Security software running on individual workloads. provide a final layer of organizational defense by filtering traffic and blocking unauthorized access attempts at the endpoint."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "IDS/IPS (Network)", "Back": "Tools monitoring and blocking malicious traffic. act as detective and preventive controls to protect organizational systems from various evolving cyber threats and adversaries."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Ingress/Egress Filtering", "Back": "Controlling traffic entering or leaving the network. prevents unauthorized organizational data exfiltration and blocks malware from communicating with external command and control servers."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Peering Security", "Back": "Protecting connections between different autonomous systems. essential for maintaining the overall security and integrity of global organizational internet routing and data transmissions between partners."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Bluetooth Security (Topic 4)", "Back": "Measures protecting short-range wireless connections. includes pairing and encryption to prevent unauthorized organizational data access and annoying attacks like bluejacking and more serious bluesnarfing."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Zigbee Security", "Back": "Protections for low-power IoT networks. requires robust organizational security controls to prevent vulnerable devices from becoming easy attack entry points into the larger corporate network."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "CDN Protection", "Back": "Distributed network delivering content securely. improves organizational website performance and provide an extra layer of defense against large-scale DDoS attacks and malicious traffic."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "SDN Automation", "Back": "Centralized network management using software. enables dynamic application of organizational security policies and improves consistency across complex and evolving infrastructure environments and system components."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "SD-WAN Security", "Back": "Securing software-defined wide area networks. integrates encryption and firewall functions to protect organizational communications between remote offices and various cloud-based applications and services."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "NFV (Virtualization)", "Back": "Virtualizing network services like firewalls and routers. allows for more flexible and scalable organizational security deployment while reducing reliance on specialized physical hardware components."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Virtual Private Cloud (VPC)", "Back": "Isolated network segment within a public cloud. allows organizations to define their own topology and security rules, protecting sensitive data in external environments."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Observability", "Back": "The ability to gain deep insights into network activity. essential for organizational threat detection and performance monitoring, identifying anomalies and potential indicators of compromise."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Traffic Shaping (Network)", "Back": "Managing network flow to prioritize critical services. ensures that essential organizational applications receive the required bandwidth while maintaining a secure and reliable communication environment."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Capacity Management (Network)", "Back": "Planning for network growth and traffic volume. ensures that organizational infrastructure can handle future needs without compromising overall security performance or operational availability."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Fault Detection (Network)", "Back": "Identifying network failures in real-time. allows for fast response and recovery to minimize organizational operational downtime and maintain the continuous availability of critical business services."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Transmission Media", "Back": "Physical materials used for data movement. includes copper and fiber optics, each requiring specific organizational security measures to prevent unauthorized tapping and interception of communications."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Physical Media Security", "Back": "Protecting cables and hardware from tampering. include locked cabinets and secure conduits to safeguard organizational data transmissions from various physical-level cyber threats and adversaries."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Signal Propagation Security", "Back": "Ensuring wireless signals don't leak beyond intended areas. requires shielding and antenna management to protect organizational information from unauthorized interception by nearby adversaries."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Access Control (NAC)", "Back": "System restricting network entry to authorized devices. it ensures that all organizational systems meet protection standards before they are allowed to connect and access resources."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Endpoint Host Security", "Back": "Protective measures applied to individual network devices. includes firewalls and EDR to block unauthorized access and malware at the specific organizational hardware endpoint level."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Collaboration Tool Security", "Back": "Securing platforms like Zoom and Teams. requires encryption and strong access controls to protect sensitive organizational communications and prevent unauthorized participation in private digital meetings."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Remote Access Security", "Back": "Measures allowing users to connect privately. includes VPNs and MFA designed to maintain organizational data confidentiality and prevent unauthorized access to sensitive internal network resources."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Backhaul Network Security", "Back": "Protecting connections between core networks and sub-networks. essential for maintaining the overall security and integrity of global organizational communications and large-scale data transmissions between systems."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Satellite Security (Network)", "Back": "Protections for data transmitted via satellite links. requires robust encryption to prevent interception over long-distance and potentially untrusted communication paths between various global organizational systems."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Third-party Network Connectivity", "Back": "Securing links to external organizational partners. requires firewalls and VPNs to ensure that cross-organizational communications are encrypted and follow established data protection policies and rules."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Telecom Provider Risk", "Back": "Security challenges from relying on external telecommunications. organizations must ensure that providers meet mandated protection standards to safeguard their data transmissions from potential cyber threats."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Hardware Support Security", "Back": "Ensuring that network equipment maintenance is secure. requires vetting technicians and monitoring activities to prevent unauthorized modifications or tampering with critical organizational digital infrastructure components."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Security Strategy", "Back": "Comprehensive plan for protecting organizational communications. combines layering, segmentation, and encryption to safeguard information assets from various evolving cyber threats and sophisticated adversary methods."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Communication Protocol Security", "Back": "Rules governing secure data exchange. security protocols like TLS and IPsec add encryption and authentication to ensure the confidentiality and integrity of all organizational transmissions."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Device Baselining", "Back": "Establishing secure configurations for all hardware. prevents configuration drift and ensures all organizational routers and switches meet minimum protection requirements against cyber attacks and unauthorized access."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Traffic Analysis", "Back": "Studying communication patterns to gain information. used by organizational administrators for monitoring but also by attackers to deduce system structures and user activities even if encrypted."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Port Security (Network)", "Back": "Restricting network entry at the physical switch port. it prevents unauthorized devices from connecting to the organizational LAN, reducing the risk of internal security breaches."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "RADIUS Authentication", "Back": "Protocol for centralized network user management. provides a standardized method for verifying identities across multiple different organizational access points and devices to ensure consistent security."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "TACACS+ Protocol", "Back": "Centralized authentication protocol for network management traffic. provides better security than RADIUS by encrypting entire organizational communication sessions between the device and management server."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "802.1X Standard", "Back": "Standard for port-based network access control. it provides an authentication mechanism for devices connecting to an organizational LAN, ensuring only authorized systems can access resources."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "EAP Framework", "Back": "Authentication framework for wireless and point-to-point links. supports multiple methods, providing flexibility and strong security for diverse organizational user environments and various system components."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "IP Spoofing (Network)", "Back": "Attack sending packets with a fake source address. used to hide identity or bypass IP-based organizational access controls and traffic filters on firewalls and routers."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "TCP SYN Flood (Attack)", "Back": "DoS attack exploiting the handshake process. adversary sends many requests but never completes connections, overwhelming organizational server resources and making services unavailable to legitimate users."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "ICMP Flood (Attack)", "Back": "DoS attack using many ping requests. aims to overwhelm organizational network bandwidth and CPU, making critical systems unresponsive and causing significant business disruption and loss."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "UDP Flood (Attack)", "Back": "DoS attack sending many UDP packets. the organizational system becomes overwhelmed by the traffic volume and the processing required to handle random port connection attempts."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Botnet (Topic 4)", "Back": "Network of compromised computers under attacker control. used to launch large-scale DDoS attacks and spread malware, threatening the overall security of organizational networks and systems."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "C2 Traffic Security", "Back": "Infrastructure used to manage botnets. securing the network requires identifying and blocking command-and-control traffic to prevent attackers from managing compromised organizational systems and assets."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Intrusion Prevention (NIPS)", "Back": "Proactive measure blocking detected cyber attacks. NIPS tools provide real-time protection by automatically responding to threats before they can cause significant harm to organizational information systems."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Baseline (Topic 4)", "Back": "Measure of normal activity and performance. used as a reference point to detect anomalies and potential security incidents that deviate from the expected organizational network behavior."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Forensic Analysis", "Back": "Capture and study of traffic for investigations. helps organizational security teams understand how a breach occurred and identify the specific actions taken by the cyber adversary."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Vulnerability Scan", "Back": "Automated process identifying known weaknesses. provides a regular check-up of the security posture and helps organizational administrators prioritize remediation and patching efforts effectively and efficiently."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Penetration Test", "Back": "Authorized simulated attack evaluating network security. identifies organizational gaps and tests the effectiveness of the defense strategy and mechanisms against real-world adversaries and sophisticated cyber threats."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Monitoring (Topic 4)", "Back": "Continuous evaluation of performance and security. helps organizational administrators identify anomalies and detect indicators of compromise before they cause significant business harm or information loss and impact."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Network Infrastructure (Topic 4)", "Back": "Physical and logical components enabling organizational communication. includes routers and switches that must be systematically tracked and secured against various evolving cyber threats and adversary methods."},
        {"Topic": "4", "Subtopic": "N/A", "Front": "Communications and Network Security", "Back": "Discipline of protecting organizational information transmissions. combines various technical and physical controls to maintain confidentiality, integrity, and availability of all network assets and communications."},

        # Topic 5: Identity and Access Management (IAM)
        {"Topic": "5", "Subtopic": "N/A", "Front": "Identification (IAM)", "Back": "The process of a user claiming an identity. involves providing a unique username or ID within the organizational environment to start the access process."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Authentication (IAM)", "Back": "Process of verifying a claimed identity. requires providing credentials like passwords or tokens to prove the user is who they claim to be in organizational systems."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Authorization (IAM)", "Back": "Process of granting or denying access to resources. determined by organizational policy and the user's permissions, ensuring they only reach authorized information assets and systems."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Accountability (IAM)", "Back": "Ability to link actions to an individual. achieved through unique IDs and audit logging, ensuring organizational users are responsible for their activities and system interactions."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Multi-factor Authentication (MFA)", "Back": "Verification using two or more credential types. significantly increases organizational security by ensuring a single compromised factor does not lead to an information system breach."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Something You Know (IAM)", "Back": "Credential based on memorized information. includes passwords and PINs, being the most common but also the most vulnerable organizational identity and access management factor."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Something You Have (IAM)", "Back": "Credential based on physical objects. includes smart cards and hardware tokens used to provide a strong secondary layer of security for organizational user identity verification."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Something You Are (IAM)", "Back": "Credential based on physical characteristics. includes biometrics like fingerprints, providing a high level of security for sensitive organizational systems while requiring careful privacy management."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Somewhere You Are (IAM)", "Back": "Credential based on physical location. uses GPS or IP address to restrict organizational system access to specific geographic areas, enhancing overall defense against remote attacks."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Something You Do (IAM)", "Back": "Credential based on behavioral patterns. includes typing speed or gait, providing continuous verification to ensure the authorized organizational user is still the one performing actions."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Single Sign-On (SSO)", "Back": "Mechanism allowing one authentication for multiple systems. it reduces password fatigue and improves organizational user experience while simplifying administrative identity management and credential oversight."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Kerberos (Topic 5)", "Back": "Ticket-based protocol providing SSO. uses a trusted third party to verify organizational identities and provide session keys, ensuring secure communication across untrusted networks."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "SAML (Topic 5)", "Back": "XML-based framework for identity federation. enables secure exchange of authentication and authorization data between different organizational security domains and various web applications and services."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "OAuth (Topic 5)", "Back": "Open standard for access delegation. allows organizational users to grant third-party apps limited access to resources without revealing their secret passwords or other sensitive credentials."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "OpenID Connect (IAM)", "Back": "Identity layer built on OAuth 2.0. allows organizational clients to verify end-user identity based on authentication performed by a trusted external authorization server and provider."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Identity Federation (IAM)", "Back": "Linking user identities across different security domains. allows users to access organizational resources in partner systems using their primary internal corporate credentials and identification."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Directory Service (IAM)", "Back": "Centralized database for users and resources. Provides a single management point for identities and access rights, enforcing consistent organizational security and protection policies."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "LDAP (Topic 5)", "Back": "Protocol for accessing directory information services. it is the primary method used by modern organizational identity management systems to maintain and query user data."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "RBAC (IAM)", "Back": "Role-Based Access Control. Grants permissions based on job function. simplifies organizational management and ensures employees only have the access they need for their duties."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "DAC (IAM)", "Back": "Discretionary Access Control. Allows resource owners to determine access. provides maximum flexibility but is difficult to manage securely in large organizational information system environments."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "MAC (IAM)", "Back": "Mandatory Access Control. Restricts access based on security labels. enforced by the system, it is the most secure organizational model for sensitive information environments."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "ABAC (IAM)", "Back": "Attribute-Based Access Control. Grants access based on user/resource characteristics. provides highly granular organizational control suitable for complex and evolving security requirements and system environments."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Rule-Based Access (IAM)", "Back": "Grants access based on predefined system rules. enforced by organizational firewalls and routers to control traffic flow and resource usage according to security policies."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Privilege Management (IAM)", "Back": "Managing and monitoring administrative access rights. requires extra protection and regular reviews to prevent unauthorized use of high-level organizational system permissions and critical information assets."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Least Privilege (IAM)", "Back": "Granting only minimum access needed for tasks. reduces organizational attack surface and limits potential damage from compromised accounts or accidental human errors and mistakes."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Need-to-Know (IAM)", "Back": "Restricting information access to individuals needing it for tasks. fundamental organizational security principle that prevents unnecessary exposure of sensitive data and information assets."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Provisioning (IAM)", "Back": "Process of creating user accounts and access. must be handled securely to ensure new organizational employees receive only the permissions required for their roles."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Deprovisioning (IAM)", "Back": "Formal process of removing access when no longer required. critical for preventing orphaned accounts and reducing unauthorized access risks in the organizational digital environment."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Access Review (IAM)", "Back": "Periodic evaluation of user permissions. ensures access still aligns with roles and identifies unnecessary entitlements for immediate removal from the organizational identity system environment."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Orphaned Account (IAM)", "Back": "Account remaining active after an employee leaves. poses significant risk as it can be used by adversaries to gain unauthorized organizational system access."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Shadow IT (IAM)", "Back": "Use of software/hardware without IT approval. creates organizational gaps by bypassing established identity management controls and oversight, leading to potential data security and privacy breaches."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Context-Aware (IAM)", "Back": "Authentication adapting based on the user's environment. uses location and time to adjust the required verification level for accessing sensitive organizational information assets."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Step-Up (IAM)", "Back": "Requiring extra verification for high-risk actions. ensures sensitive organizational activities receive more security, even if the user is already authenticated to the information system."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Continuous Verification", "Back": "Ongoing identity checking during a session. uses behavioral factors to ensure the authorized organizational user is still the one performing actions within the system."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Biometric Error Rate (Topic 5)", "Back": "Measure of accuracy for characteristics systems. includes FAR and FRR, which must be balanced to ensure effective organizational security and user convenience."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Crossover Error Rate (Topic 5)", "Back": "The point where FAR and FRR are equal. most important metric for evaluating overall organizational biometric system accuracy and performance during identity management activities."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Password Policy (IAM)", "Back": "Rules defining required complexity and rotation frequency. aims to reduce brute-force risks and ensure organizational user credentials remain secure against various cyber threats."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Password Manager (IAM)", "Back": "Tool storing and generating strong credentials. it improves organizational security by encouraging the use of unique and complex passwords for every system and application."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "PAM specialized Tools", "Back": "Systems securing administrative accounts. provides extra organizational protection including session recording and just-in-time provisioning to reduce the time high-level credentials are exposed."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Just-In-Time (IAM)", "Back": "Granting administrative permissions only when required. reduces the organizational attack surface and limits the risk of credential theft for high-level information system access."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "UEBA (IAM)", "Back": "User Behavior Analytics. monitoring activity to detect anomalies. helps identify potential organizational threats like account compromise or malicious insider behavior by identifying deviations from normal patterns."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Identity Proofing (IAM)", "Back": "Verifying real-world identity before granting digital credentials. essential first step in ensuring the overall integrity and trustworthiness of the organizational identity management system."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Identity Governance (IAM)", "Back": "Strategic management of user identities. ensures IAM practices align with business goals and comply with mandated organizational and legal data protection requirements and standards."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Access Certification (IAM)", "Back": "Formal review of user permissions. ensures employees only have currently needed access and identifies potential organizational security risks for immediate remediation and corrective action."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Entitlement Management (IAM)", "Back": "Lifecycle management of user access rights. ensures that entitlements are granted and removed consistently and securely across all organizational systems and sensitive information assets."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Role Mining (IAM)", "Back": "Analyzing activity to identify common access patterns. helps organizations define and refine their RBAC roles, improving the overall efficiency of identity management processes."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Delegated Administration (IAM)", "Back": "Assigning administrative tasks to designated groups. it improves organizational efficiency while maintaining strong security controls by reducing the burden on central IT departments."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Self-Service Reset (IAM)", "Back": "Allowing users to reset passwords without IT assistance. improves experience and reduces organizational costs while requiring strong secondary verification to maintain system-wide security."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Digital Identity (IAM)", "Back": "Representation of an individual in computer systems. includes attributes used to authenticate and authorize organizational users for various resources and information assets and systems."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Access Control Model (IAM)", "Back": "Framework for managing resource access. includes models like RBAC and MAC, providing different balances of security and organizational administrative management complexity and flexibility."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "IDaaS (IAM)", "Back": "Identity as a Service. Cloud-based management solution. simplifies deployment and provides scalable identity management for organizations with diverse and evolving IT environments and application needs."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "IAM Lifecycle Phase", "Back": "Stages of identity management. includes provisioning and deprovisioning, each requiring specific organizational security controls to ensure constant data protection throughout the entire user cycle."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Access Control Mechanism (IAM)", "Back": "Technical tool enforcing access policies. includes passwords and encryption designed to maintain organizational confidentiality and integrity of all digital resources and information assets."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Authentication Protocol (IAM)", "Back": "Rules governing identity verification. protocols like SAML provide secure methods for exchanging data across organizational domains and various untrusted network and system environments."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Authorization Policy (IAM)", "Back": "Document defining which users reach specific resources. enforced by the system, it ensures access follows organizational security policies and the principle of least privilege."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Audit Logging (IAM)", "Back": "Recording access and security events. provides a detailed record for compliance and forensic investigations, ensuring every organizational user is accountable for their system activities."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Identity Provider (IdP) (IAM)", "Back": "Service authenticating users for other systems. essential for identity federation and enabling SSO across diverse organizational and external application environments and service platforms."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Service Provider (SP) (IAM)", "Back": "Application relying on an IdP for authentication. uses identity data to authorize organizational users for specific resources and information assets within its environment."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Trust Relationship (IAM)", "Back": "Agreement between systems to accept authentication data. foundation for organizational identity federation and enabling secure cross-domain access for authorized users and system components."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Attribute-based Access (IAM)", "Back": "Grants access using user/resource characteristics. used in ABAC to make granular organizational decisions based on location, role, and other relevant contextual and technical factors."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Permission (IAM)", "Back": "The right to perform an action on a resource. assigned to organizational users or roles to enable them to carry out their business responsibilities."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Privilege (IAM)", "Back": "High-level permission for administrative users. allows sensitive system tasks and requires extra organizational monitoring to prevent unauthorized use of critical information assets and systems."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Access Token (IAM)", "Back": "Credential proving authorization for a resource. issued by servers, allowing organizational users to access applications without re-authenticating during a single active session or interaction."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Session Management (IAM)", "Back": "Tracking user interactions with systems. ensures sessions remain secure and are automatically terminated after inactivity to prevent unauthorized access to organizational resources and information."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Session Hijacking (IAM)", "Back": "Attack where an adversary takes over an active interaction. allows unauthorized access to organizational resources without knowing the user's secret login and access credentials."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Brute Force (IAM Attack)", "Back": "Trial-and-error method to guess credentials. attackers try all combinations until the correct organizational password or key is found by their malicious software and tools."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Dictionary Attack (IAM)", "Back": "Brute force using common password lists. faster than trying all combinations, making strong and unique organizational credentials essential for protecting sensitive information and systems."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Rainbow Table (IAM)", "Back": "Attack using precomputed hashes. quickly cracks passwords that aren't salted, making the use of salt a critical organizational requirement for protecting stored user authentication data."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Social Engineering (IAM)", "Back": "Manipulating individuals into revealing credentials. exploits human psychology to bypass organizational identity and access management controls and mechanisms, leading to potential data breaches and system compromises."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Phishing (IAM Attack)", "Back": "Deceptive attempts to steal credentials. uses fraudulent emails and websites to trick organizational users into providing sensitive system access information to malicious cyber adversaries."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Credential Stuffing (IAM)", "Back": "Using leaked pairs to gain unauthorized access. exploits organizational users who reuse the same passwords across multiple different personal and business systems and application environments."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "IAM Security Control (Topic 5)", "Back": "Mechanism protecting identities and access. combines technical and administrative measures to maintain confidentiality, integrity, and availability of all critical organizational information resources and systems."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Information Privacy (IAM)", "Back": "Right of individuals to control personal data use. protecting privacy is a critical requirement for organizational identity systems and ensures compliance with global laws."},
        {"Topic": "5", "Subtopic": "N/A", "Front": "Compliance Assessment (IAM)", "Back": "Evaluating adherence to identity management laws. identifies gaps and ensures all mandated organizational controls are functioning effectively to avoid severe financial and legal penalties."},
