def upload_data(data):
    print(f"Uploading {len(data['flashcards'])} flashcards to Google Sheet...")
    try:
        response = requests.post(APPS_SCRIPT_URL, json=data, timeout=120)
        if response.status_code == 200:
            print("Successfully uploaded all flashcards!")
            return True
        else:
            print(f"Failed to upload. Status: {response.status_code}")
            print(f"Response: {response.text}")
            return False
    except Exception as e:
        print(f"Error uploading: {e}")
        return False

if __name__ == "__main__":
    upload_data(data)
